BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?client ?clientName ?supplier ?supplierName WHERE {
  ?supplier vocab:NamedElement_name ?supplierName .
  FILTER(CONTAINS(LCASE(STR(?supplierName)), LCASE("APS")))

  ?dependency rdf:type vocab:dependency .
  ?dependency vocab:Dependency_supplier ?supplier .
  ?dependency vocab:Dependency_client ?client .

  OPTIONAL { ?client vocab:NamedElement_name ?clientName }
  OPTIONAL { ?supplier vocab:NamedElement_name ?supplierName2 }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?other ?otherName WHERE {
  ?dep rdf:type vocab:dependency .

  # APS is modeled as elements (package/block/docs). We treat any entity whose name contains 'TMT-APS'
  # as part of the APS context, and ask who depends on/off from that.
  {
    ?dep vocab:Dependency_supplier ?apsEntity .
    ?apsEntity vocab:NamedElement_name ?apsName .
    FILTER(CONTAINS(LCASE(STR(?apsName)), LCASE("TMT-APS")))
    ?dep vocab:Dependency_client ?other .
  }
  UNION
  {
    ?dep vocab:Dependency_client ?apsEntity .
    ?apsEntity vocab:NamedElement_name ?apsName .
    FILTER(CONTAINS(LCASE(STR(?apsName)), LCASE("TMT-APS")))
    ?dep vocab:Dependency_supplier ?other .
  }

  OPTIONAL { ?other vocab:NamedElement_name ?otherName . }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?dep ?depName ?apsEntity ?apsName ?other ?otherName WHERE {
  ?dep rdf:type vocab:dependency .

  {
    ?dep vocab:Dependency_supplier ?apsEntity .
    ?apsEntity vocab:NamedElement_name ?apsName .
    FILTER(CONTAINS(LCASE(STR(?apsName)), LCASE("aps")))

    ?dep vocab:Dependency_client ?other .
    OPTIONAL { ?other vocab:NamedElement_name ?otherName }
    OPTIONAL { ?dep vocab:NamedElement_name ?depName }
  }
  UNION
  {
    ?dep vocab:Dependency_client ?apsEntity .
    ?apsEntity vocab:NamedElement_name ?apsName .
    FILTER(CONTAINS(LCASE(STR(?apsName)), LCASE("aps")))

    ?dep vocab:Dependency_supplier ?other .
    OPTIONAL { ?other vocab:NamedElement_name ?otherName }
    OPTIONAL { ?dep vocab:NamedElement_name ?depName }
  }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?depName ?dep ?pred ?val WHERE {
  ?dep rdf:type vocab:dependency .
  OPTIONAL { ?dep vocab:NamedElement_name ?depName . }
  ?dep ?pred ?val .
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?external ?externalName ?apsSide ?apsSideName WHERE {
  ?dep rdf:type vocab:dependency .
  ?dep vocab:Dependency_client ?client .
  ?dep vocab:Dependency_supplier ?supplier .

  ?client vocab:NamedElement_qualifiedName ?clientQName .
  ?supplier vocab:NamedElement_qualifiedName ?supplierQName .

  FILTER(
    (CONTAINS(STR(?supplierQName), "TMT-APS%20DDD") && CONTAINS(STR(?clientQName), "TMT-APS"))
    || (CONTAINS(STR(?clientQName), "TMT-APS%20DDD") && CONTAINS(STR(?supplierQName), "TMT-APS"))
  )

  BIND(
    IF(CONTAINS(STR(?supplierQName), "TMT-APS%20DDD"), ?supplier, ?client) AS ?apsSide
  )
  OPTIONAL { ?apsSide vocab:NamedElement_name ?apsSideName . }

  BIND(
    IF(?apsSide = ?supplier, ?client, ?supplier) AS ?external
  )
  OPTIONAL { ?external vocab:NamedElement_name ?externalName . }
}
LIMIT 25

